2.4 Code Examples

library(palmerpenguins)
library(tidyverse)

penguins |&gt;
  drop_na(bill_length_mm) |&gt;
  summarise(
    M   = mean(bill_length_mm),
    Var = var(bill_length_mm),
    SD  = sd(bill_length_mm)
  )


penguins |&gt;
  drop_na(bill_length_mm) |&gt;
  mutate(z_bill = (bill_length_mm - mean(bill_length_mm)) / sd(bill_length_mm)) |&gt;
  select(species, bill_length_mm, z_bill) |&gt;
  head(8)

5.4 Code Examples

library(palmerpenguins)
library(tidyverse)

adelie &lt;- penguins |&gt;
  filter(species == "Adelie") |&gt;
  drop_na(flipper_length_mm)

t.test(adelie$flipper_length_mm, mu = 190)


penguins |&gt;
  drop_na(bill_length_mm, bill_depth_mm) |&gt;
  slice_head(n = 20) |&gt;
  with(t.test(bill_length_mm, bill_depth_mm, paired = TRUE))

6.3 Code Examples

library(palmerpenguins)
library(tidyverse)

penguins |&gt;
  drop_na(flipper_length_mm) |&gt;
  group_by(species) |&gt;
  summarise(M = mean(flipper_length_mm), SD = sd(flipper_length_mm), n = n())


penguins_clean &lt;- penguins |&gt; drop_na(flipper_length_mm)

aov(flipper_length_mm ~ species, data = penguins_clean) |&gt; summary()

7.3 Code Examples

library(palmerpenguins)
library(tidyverse)

penguins |&gt;
  drop_na(flipper_length_mm, sex) |&gt;
  group_by(species, sex) |&gt;
  summarise(M = mean(flipper_length_mm), .groups = "drop")


penguins_clean &lt;- penguins |&gt; drop_na(flipper_length_mm, sex)

aov(flipper_length_mm ~ species * sex, data = penguins_clean) |&gt; summary()
